import React from 'react';
import Header from '../../components/public/Header';
import Footer from '../../components/public/Footer';
import ProductCard from '../../components/public/ProductCard';
import { useAuth } from '../../context/AuthContext';

const HomePage = () => {
  const { loginAsAdmin } = useAuth(); // 💥 ESTA LÍNEA ES LA CLAVE

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col">
      <div>
        <h1>Página Pública</h1>
        <button onClick={loginAsAdmin} className="bg-blue-500 text-white p-2 rounded">
          Iniciar sesión como Admin
        </button>
      </div>

      <Header />
      <main className="main-content">
        <h2 className="section-title fade-in">Nuestras Zapatillas</h2>
        <p className="section-description fade-in">Explora nuestra amplia gama...</p>

        <div className="card-grid grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6 p-4">
          <ProductCard title="Air Max" category="Running" price="89.99" originalPrice="120.00" discount="25" tag="NUEVO" />
          <ProductCard title="Urban Street Pro" category="Casual" price="75.99" />
          <ProductCard title="Elite Jumper X" category="Basketball" price="129.99" originalPrice="150.00" discount="13" tag="HOT" />
        </div>
      </main>
      <Footer />
    </div>
  );
};

export default HomePage;
